import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  Box,
  IconButton,
  Tooltip,
  CircularProgress,
  Alert,
  Button
} from '@mui/material';
import {
  Close,
  Refresh
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const FinishedOperationsModal = ({ open, onClose, hideValues = false }) => {
  const [positions, setPositions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [refreshing, setRefreshing] = useState(false);
  const [rawData, setRawData] = useState(null);

  const loadFinishedPositions = async () => {
    try {
      setLoading(true);
      setError('');
      const response = await dashboardService.getFinishedPositions();
      if (response && response.positions) {
        setPositions(response.positions);
      }
    } catch (err) {
      console.error('Erro ao carregar operações finalizadas:', err);
      setError('Erro ao carregar operações');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (open) {
      loadFinishedPositions();
    }
  }, [open]);

  const handleRefresh = async () => {
    setRefreshing(true);
    await loadFinishedPositions();
    setRefreshing(false);
  };

  const formatDateTime = (timestamp) => {
    if (!timestamp) return '-';
    const date = new Date(parseInt(timestamp));
    return date.toLocaleString();
  };

  const formatValue = (value) => {
    if (value === undefined || value === null || value === '') return '-';
    const numValue = parseFloat(value);
    return numValue.toFixed(4);
  };

  // Função para traduzir os títulos das colunas
   const getColumnTitle = (key) => {
     const translations = {
       'symbol': 'Par',
       'openAvgPrice': 'Preço de Abertura',
       'closeAvgPrice': 'Preço de Fechamento',
       'holdSide': 'Lado',
       'openTotalPos': 'Total Abertura',
       'closeTotalPos': 'Total Fechamento',
       'pnl': 'Lucro / Prejuízo',
       'marginMode': 'Modo Margem',
       'ctime': 'Data e hora da Abertura',
       'utime': 'Data e hora do Fechamento',
       'positionId': 'Número da Operação',
       'comissao': 'Comissão'
     };
     return translations[key] || key;
   };

   // Função para traduzir valores específicos
   const translateValue = (key, value) => {
     if (key === 'marginMode') {
       const marginModeTranslations = {
         'crossed': 'Cruzada',
         'isolated': 'Isolada'
       };
       return marginModeTranslations[value] || value;
     }
     return value;
   };

  // Função para obter todas as chaves únicas dos objetos com ordem personalizada
  const getAllKeys = (data) => {
    if (!Array.isArray(data) || data.length === 0) return [];
    const keys = new Set();
    data.forEach(item => {
      Object.keys(item).forEach(key => keys.add(key));
    });

    // Ordem personalizada das colunas (excluindo netProfit e marginCoin)
    const priorityOrder = [
      'symbol',
      'openAvgPrice',
      'closeAvgPrice', 
      'holdSide',
      'openTotalPos',
      'closeTotalPos',
      'pnl',
      'comissao', // Nova coluna calculada
      'marginMode',
      'ctime',
      'utime',
      'positionId'
    ];

    const allKeys = Array.from(keys);
    const orderedKeys = [];

    // Adiciona as chaves na ordem de prioridade (excluindo colunas desnecessárias)
    priorityOrder.forEach(key => {
      if (key === 'comissao' || (allKeys.includes(key) && key !== 'netProfit' && key !== 'marginCoin' && key !== 'closeFee' && key !== 'openFee' && key !== 'totalFunding')) {
        orderedKeys.push(key);
      }
    });

    // Adiciona as chaves restantes que não estão na lista de prioridade (excluindo colunas desnecessárias)
    allKeys.forEach(key => {
      if (!priorityOrder.includes(key) && key !== 'netProfit' && key !== 'marginCoin' && key !== 'closeFee' && key !== 'openFee' && key !== 'totalFunding') {
        orderedKeys.push(key);
      }
    });

    return orderedKeys;
  };

  // Função para calcular a comissão (PNL x 35% apenas para operações positivas)
  const calculateCommission = (pnl) => {
    if (!pnl || isNaN(parseFloat(pnl))) return 0;
    const pnlValue = parseFloat(pnl);
    // Só cobra comissão se o PNL for positivo (lucro)
    return pnlValue > 0 ? pnlValue * 0.35 : 0;
  };

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth={false}
      PaperProps={{
        sx: {
          width: '90vw',
          maxHeight: '90vh',
          margin: '20px'
        }
      }}
    >
      <DialogTitle>
        <Box display="flex" justifyContent="space-between" alignItems="center">
          <Typography variant="h6">Operações Finalizadas</Typography>
          <Box>
            <Tooltip title="Atualizar">
              <IconButton onClick={handleRefresh} disabled={refreshing}>
                <Refresh />
              </IconButton>
            </Tooltip>
            <Tooltip title="Fechar">
              <IconButton onClick={onClose}>
                <Close />
              </IconButton>
            </Tooltip>
          </Box>
        </Box>
      </DialogTitle>

      <DialogContent sx={{ p: 2, overflowX: 'hidden' }}>
        {loading ? (
          <Box display="flex" justifyContent="center" p={3}>
            <CircularProgress />
          </Box>
        ) : error ? (
          <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>
        ) : positions.length === 0 ? (
          <Alert severity="info">Nenhuma operação finalizada encontrada</Alert>
        ) : (
          <>
            <TableContainer 
              component={Paper} 
              sx={{ 
                mb: 2,
                width: '100%',
                overflowX: 'auto',
                '& .MuiTable-root': {
                  minWidth: '100%',
                  borderCollapse: 'separate',
                  borderSpacing: '0'
                }
              }}
            >
              <Table size="small" stickyHeader>
                <TableHead>
                  <TableRow>
                    {getAllKeys(positions).map((key) => (
                      <TableCell 
                        key={key}
                        sx={{
                          whiteSpace: 'nowrap',
                          backgroundColor: 'background.paper',
                          fontWeight: 'bold',
                          textAlign: 'center'
                        }}
                      >
                        {getColumnTitle(key)}
                      </TableCell>
                    ))}
                  </TableRow>
                </TableHead>
                <TableBody>
                  {positions.map((position, index) => (
                    <TableRow key={index}>
                      {getAllKeys(positions).map((key) => (
                        <TableCell 
                          key={key}
                          sx={{
                            whiteSpace: 'nowrap',
                            maxWidth: '200px',
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                            textAlign: 'center',
                            ...(key === 'comissao' && calculateCommission(position.pnl) > 0 && {
                              color: '#4caf50 !important',
                              fontWeight: 'bold'
                            })
                          }}
                        >
                          {key === 'comissao' ? 
                            formatValue(calculateCommission(position.pnl)) :
                            key === 'symbol' ? 
                              <>
                                {position[key]}
                                {position.leverage && 
                                  <Typography 
                                    component="span" 
                                    sx={{ 
                                      fontSize: '0.7rem', 
                                      ml: 0.5,
                                      fontWeight: 'bold',
                                      color: position.holdSide?.toLowerCase() === 'long' ? '#4caf50' : '#f44336'
                                    }}
                                  >
                                    {position.leverage}x
                                  </Typography>
                                }
                              </> :
                            key.toLowerCase().includes('time') ? 
                              formatDateTime(position[key]) :
                              ['profit', 'totalFee', 'openAvgPrice', 'closeAvgPrice', 'takeProfit', 'stopLoss', 'pnl'].includes(key) ?
                                formatValue(position[key]) :
                                translateValue(key, position[key]?.toString() || '-')
                          }
                        </TableCell>
                      ))}
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          </>
        )}
      </DialogContent>
    </Dialog>
  );
};

export default FinishedOperationsModal;
